def group_anagrams(words):
    from collections import OrderedDict
    groups = OrderedDict()
    for word in words:
        key = ''.join(sorted(word.lower()))
        if key not in groups:
            groups[key] = []
        groups[key].append(word)
    return list(groups.values())
